UPDATE /* @SQLID=SUB0202_0301-01_2#Sql002 */ FOREIGN_CONSIGNMENT_ORDER
SET 
    ACCEPT_ORDER_NO = #{req.acceptOrderNo}
    ,ACCEPT_ORDER_SUB_NO = #{req.acceptOrderSubNo}
    ,ORDER_DATE = #{req.orderDate}
    ,ORDER_TIME = TO_DATE(#{req.orderTime}, 'YYYY-MM-DD HH24:MI:SS')
    ,TRADE_LIMIT_DATE = #{req.tradeLimitDate}
    ,API_ERROR_CODE = NULL
    ,API_STATUS_CODE = #{req.apiStatusCode}
    ,API_MESSAGE = NULL
    ,UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    ,UPDATE_USER = #{req.updateUser}
WHERE 
    IFA_ORDER_NO = #{req.ifaOrderNo}
    AND IFA_ORDER_SUB_NO = #{req.ifaOrderSubNo}

