SET 
    ,API_ERROR_CODE = #{req.apiErrorCode}
    ,API_STATUS_CODE = #{req.apiStatusCode}
    ,API_MESSAGE = #{req.apiMsg}
    ,UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    ,UPDATE_USER = #{req.updateUser}
WHERE 
    IFA_ORDER_NO = #{req.ifaOrderNo}
    AND IFA_ORDER_SUB_NO = #{req.ifaOrderSubNo}
